    var zzbm = Java.use("com.google.android.gms.internal.measurement.zzbm");
    zzbm.zzb.implementation = function(i2, parcel) {
        console.log("[+] Intercepting IPC Transaction ID: " + i2);
        // You can dump the Parcel data here before it reaches the remote service
        return this.zzb(i2, parcel);
    };
});
```
By intercepting this, one can view the contents of the `Parcel` (which may contain transaction IDs, session metadata, or hardware-backed keystore requests) before they are sent to the system service.

